"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[32004],{89790:(A,t,i)=>{i.r(t),i.d(t,{data:()=>e});const e={key:"v-785aa7e6",path:"/C#/%E8%87%AA%E5%AE%9A%E4%B9%89%E6%8E%A7%E4%BB%B6/11.%E5%9B%9E%E4%BC%A0%E4%BA%8B%E4%BB%B6%E5%8E%9F%E7%90%86.html",title:"自定义控件(十一)-回传事件原理",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"C#/自定义控件/11.回传事件原理.md"}},1692:(A,t,i)=>{i.r(t),i.d(t,{default:()=>a});const e=(0,i(57293).uE)('<h1 id="自定义控件-十一-回传事件原理" tabindex="-1"><a class="header-anchor" href="#自定义控件-十一-回传事件原理" aria-hidden="true">#</a> 自定义控件(十一)-回传事件原理</h1><p>当页面发送到客户端浏览器后，用户对页面的操作本质上只会触发客户端的事件。比如用户点击一个<input type="button">按钮，触发的click事件其实只不过是客户端按钮的click事件，那么事件又是怎么&quot;传染&quot;到服务器,触发服务器控件的呢。</p><p>我们分析一下.net的LinkButton控件</p><p>在网页中添加LinkButton控件，查看源代码</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210855281.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>一个a标签竟然能够与服务器进行交互，是怎么做到的呢</p><p>所有奥秘都在__doPostBack()函数中。</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210855241.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>ASP.NET在所有需要回传的页面中注册两个隐藏表单域和一段javascript脚本,以支持所有控件的回传。</p><p>结合LinktButton源代码，我们可以知道，需要触发服务器端事件的控件其实是调用的__doPostBack函数,分别把事件源和事件的参数赋值给了 两个隐藏域:__EVENTTARGET和__EVENTARGUMENT，然后把表单提交到服务端。</p><p>在页面中添加一个div，给他添加__doPostBack函数</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;div id=&quot;btn&quot; onclick=&quot;__doPostBack(&#39;btn&#39;,&#39;&#39;)&quot; style=&#39;width:100px;height:100px;background:blue;&#39;&gt;&lt;/div&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>点击div并没有反应，这是为什么呢？我们查看页面源代码</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210855257.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>发现页面中并没有注册__PostBackEvent事件</p><p>在页面中添加一个LinkButton,发现点击div刷新了页面</p><p>把LinkButton换成Button,发现点击div不会刷新页面</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210855246.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>Button解析成html后是submit本身就能提交表单，asp.net不会为他注册__doPostBack事件。</p><p>当然也可以自己在页面中添加隐藏域和__doPostBack函数，也能实现回传事件</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>    &lt;input name=&quot;__EVENTTARGET&quot; id=&quot;__EVENTTARGET&quot; value=&quot;&quot; type=&quot;hidden&quot;&gt;\n  &lt;input name=&quot;__EVENTARGUMENT&quot; id=&quot;__EVENTARGUMENT&quot; value=&quot;&quot; type=&quot;hidden&quot;&gt;\n    &lt;script type=&quot;text/javascript&quot;&gt;\n//&lt;![CDATA[\n        var theForm = document.forms[&#39;form1&#39;];\n        if (!theForm) {\n            theForm = document.form1;\n        }\n        function __doPostBack(eventTarget, eventArgument) {\n            if (!theForm.onsubmit || (theForm.onsubmit() != false)) {\n                theForm.__EVENTTARGET.value = eventTarget;\n                theForm.__EVENTARGUMENT.value = eventArgument;\n                theForm.submit();\n            }\n        }\n//]]&gt;\n&lt;/script&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p>',23),n={},a=(0,i(63243).Z)(n,[["render",function(A,t){return e}]])},63243:(A,t)=>{t.Z=(A,t)=>{const i=A.__vccOpts||A;for(const[A,e]of t)i[A]=e;return i}}}]);